"""
MKT Context Commentary — 1 Corinthians chapters 1-4
Run: python3 scripts/zc-context-1corinthians-1-4.py

Source data used:
- data/interlinear/1corinthians.json
- data/translation/draft/mediating/1corinthians.json
- data/translation/notes/1corinthians.json

Key historical context for chs 1-4:
- Corinth: refounded 44 BCE as Roman colony; ca. 200,000 inhabitants by Paul's time; biennial
  Isthmian Games made it a rhetorical showcase; Acts 18 anchor date is ca. 51 CE (Gallio)
- Paul wrote 1 Corinthians ca. 53-54 CE from Ephesus (16:8) after receiving oral report from
  Chloe's household (1:11) and a written inquiry (7:1)
- Apollos: Alexandrian-trained Jewish rhetor (Acts 18:24-28); Paul's 'planting/watering' language
  and the Apollos vs Paul factions are the social engine of chs 1-4
- The wisdom-rhetoric debate: Corinth hosted major rhetorical competitions; the Sophists measured
  status by eloquence; Paul's deliberate refusal of 'lofty words' (2:1) was a calculated counter
- No straight double-quote characters in value strings; typographic quotes used throughout
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CONTEXT = {
  "1": {
    "1": '<p>The Pauline letter-formula follows the standard Greek epistolary convention: sender, recipient, greeting (<em>chairein</em>). Paul adapts it with theological freight: his apostleship is <em>klētos apostolos</em> (called apostle) — not self-appointed but divinely commissioned. Sosthenes appears in Acts 18:17 as the synagogue ruler beaten before Gallio; if this is the same person, his co-authorship signals his subsequent conversion and standing in the Corinthian community.</p>',
    "2": '<p>Corinth\'s church (<em>ekklēsia</em>) — a term carrying both Jewish-synagogue resonance (the LXX rendering of <em>qahal</em>, the assembly of Israel) and Greco-Roman political resonance (the <em>ekklēsia</em> was the citizen assembly). Paul\'s audience would hear the term as simultaneously Jewish covenant-assembly and civic assembly. <em>Hēgiasmenois en Christō Iēsou</em> (sanctified in Christ Jesus): perfect passive participle — a completed act of consecration establishing their current standing. The address extends to <em>panta topō</em> (every place) — the letter circulates beyond Corinth.</p>',
    "3": '<p>The greeting <em>charis kai eirēnē</em> (grace and peace) blends the Greek epistolary <em>chairein</em> (greetings) with the Jewish <em>shalom</em> — a bilingual greeting that signals a community spanning ethnic boundaries. Paul uses this formula in every letter; its origin is likely his own liturgical practice adapted from Jewish synagogue greetings.</p>',
    "4": '<p>Thanksgiving sections (<em>eucharistō</em>) were standard in Greco-Roman letters but Paul fills his with theological content. The thanks is directed <em>peri hymōn</em> (concerning you) — personalized, not formulaic. The ground is <em>epi tē chariti tou Theou</em> (because of the grace of God): grace is the initiating divine act, not the Corinthians\' achievement. This sets the tone for the entire letter\'s confrontation with Corinthian pride.</p>',
    "5": '<p>Enriched <em>en panti logō kai pasē gnōsei</em> (in all speech and all knowledge) — Paul acknowledges the Corinthians\' genuine gifts before critiquing their misuse. <em>Logos</em> and <em>gnōsis</em> are precisely the capacities the Corinthians prized and competed over. The thanksgiving grants them as genuine divine endowments, which sharpens the subsequent critique: the problem is not that they lack gifts but that they misuse them.</p>',
    "6": '<p>The testimony of Christ being confirmed among them recalls Paul\'s founding preaching mission in Acts 18:1-18: Paul stayed 18 months in Corinth (v. 11), establishing a community that itself became evidence of the gospel\'s power. The Corinthian community is a living confirmation of the apostolic witness.</p>',
    "7": '<p><em>Hystereisthe</em> (you do not lack) — present tense: the gifts are currently operative. <em>Charisma</em> (spiritual gift): Paul uses this term later in detail (chs 12-14); here he anticipates the full treatment. <em>Apokalypsin</em> (revelation/apocalypse of our Lord Jesus Christ): the eschatological horizon shapes all Pauline ethics; the community awaits the Lord\'s unveiling, which will also be the Day of judgment (v. 8).</p>',
    "8": '<p><em>Heos telous</em> (to the end) — divine faithfulness guarantees perseverance to the eschatological consummation. <em>Anengklētous en tē hēmera tou Kyriou</em> (blameless on the Day of the Lord): the Day of the Lord language comes from the Hebrew prophets (Amos 5:18-20; Joel 2:1); Paul applies it to the Parousia of Jesus. The concern about blamelessness on that Day becomes the context for all of Paul\'s ethical teaching in the letter.</p>',
    "9": '<p><em>Pistos ho Theos</em> (God is faithful) — the bedrock theological claim. In Jewish tradition, divine faithfulness (<em>emunah</em>/<em>pistis</em>) is God\'s covenant-keeping reliability: what he promises, he performs. The call into <em>koinōnia</em> (fellowship, partnership) with his Son is Paul\'s first use of the <em>koinōnia</em> term, which becomes central to his understanding of the Lord\'s Supper (10:16-17).</p>',
    "10": '<p><em>Parakalō</em> (I appeal, I urge) — the standard Pauline paraenetic verb, carrying the weight of apostolic exhortation without the authoritative command (<em>parangellō</em>). <em>Dia tou onomatos tou Kyriou Iēsou Christou</em> (in the name of the Lord Jesus Christ): the appeal is in the name, invoking Christ\'s authority for the unity request. <em>Katērtismenoi</em> (perfectly joined, completely united) — the technical term for mending fishing nets or setting a fractured bone: the community needs repair, not merely encouragement.</p>',
    "11": '<p>Chloe\'s household (<em>tōn Chloes</em>): Chloe is mentioned by name — a woman who owned a household large enough to have representatives traveling between Corinth and Ephesus. This is among the earliest evidence for women\'s leadership roles in Pauline communities. The <em>eris</em> (quarrels, contentions) reported by her household is the concrete problem Paul addresses: factional rivalry structured around patron-client allegiances to different apostolic figures.</p>',
    "13": '<p>Three rhetorical questions attack the absurdity of the factions: Was Christ divided? Was Paul crucified for you? Were you baptized into Paul\'s name? Baptism in the ancient world created an allegiance-bond — to be baptized into someone\'s name was to become their property/client. Paul denies the factions any theological legitimacy by pointing to the exclusive claims of Christ\'s crucifixion and baptism: both belong to Christ alone, not to apostolic factions.</p>',
    "14": '<p>Crispus was the Corinthian synagogue ruler who converted (Acts 18:8) — a significant patron-figure whose conversion would have been socially and financially consequential. Gaius hosted the entire Corinthian church (Rom 16:23) — clearly a man of means with a house large enough for the assembly. Paul\'s relief at not having baptized them himself reflects his concern that personal baptism creates personal loyalty bonds that would fuel the faction problem.</p>',
    "15": '<p>The danger Paul avoids: if he had baptized many in Corinth, his followers could claim special status as Paul\'s clients through the baptismal bond. The <em>eis to emon onoma</em> (into my name) would have been precisely the language of Greco-Roman religious initiation and patron-client allegiance. Paul\'s sparse baptizing practice is a deliberate counter to patronal religion.</p>',
    "16": '<p>The parenthetical admission (yes, I also baptized the household of Stephanas) is a genuine aside — Paul is thinking aloud rather than composing a formal argument. Stephanas is named three times in 1 Corinthians (1:16; 16:15, 17) as a founding convert and patron-figure. Paul\'s forgetfulness about other baptisms suggests he delegated most baptisms to co-workers — consistent with his practice in Acts (20:4; Rom 16:1-16).</p>',
    "17": '<p><em>Euaggelizesthai</em> (to preach the gospel): Paul\'s self-description of his primary calling. The phrase <em>ouk en sophia logou</em> (not with wisdom of words) is a reference to Sophistic rhetoric, which Paul systematically avoided in Corinth. The Sophists competed for fees and prestige by displaying their eloquence (<em>logos</em>); Paul\'s deliberate refusal of their style was a counter-cultural statement that the message itself carried the power, not the messenger\'s rhetorical artistry. His arrival in Corinth after Athens (Acts 17:32-18:1) may have sharpened this decision.</p>',
    "18": '<p>The cross as social shame: crucifixion was used by Romans specifically for slaves, rebels, and enemies of the state — the most dishonorable death possible in the Roman world. Cicero wrote that the very word <em>crux</em> (cross) should be kept far from the eyes and ears of Roman citizens (Pro Rabirio 5.16). Jewish sensibility added the Deuteronomic curse: anyone hung on a tree is cursed by God (Deut 21:23, which Paul applies explicitly in Gal 3:13). To preach a crucified savior was to preach a shamed, defeated, cursed figure — precisely what Paul calls <em>mōria</em> (foolishness) to Greeks and <em>skandalon</em> (stumbling block, scandal) to Jews.</p>',
    "19": '<p>Paul cites Isa 29:14 (LXX): God will destroy the wisdom of the wise and nullify the intelligence of the intelligent. Isaiah\'s original context is God\'s judgment on Jerusalem\'s advisors who sought political alliance with Egypt instead of trust in YHWH. Paul applies it to the Corinthian wisdom-competition: the same divine pattern — God overturning human strategic cleverness — is now operative in the gospel.</p>',
    "20": '<p>Three social-philosophical figures: <em>sophos</em> (the philosopher/sage), <em>grammateus</em> (the scribe/Torah scholar, Jewish), <em>syzētētēs</em> (the debater/disputer, Greek rhetor). All three were recognized prestige-figures in their respective communities. Paul asks: where are they? — meaning: the cross has rendered the entire apparatus of human wisdom irrelevant. <em>Ho aion houtos</em> (this age): Paul\'s eschatological framing — the present age is temporary and its wisdom structures will pass.</p>',
    "21": '<p>The <em>sophia tou Theou</em> (wisdom of God) here is not a divine attribute but a divine strategy: God\'s choice to reveal himself through the cross rather than through philosophical demonstration. <em>Hē mōria tou kērygmatos</em> (the foolishness of the proclamation): the <em>kērygma</em> is the announcement, the proclaimed word — Paul makes the content, not the technique, the object of attack. Natural theology (knowing God through worldly wisdom) has failed; God chose the path of proclamation instead.</p>',
    "22": '<p>Jewish expectation of signs (<em>sēmeia</em>) was rooted in the Exodus tradition: Moses validated his mission through miraculous signs (Exod 4:1-9), and the prophetic tradition expected the messianic age to be authenticated by miracles (Isa 35:5-6; John 2:18; Matt 12:38). Greek pursuit of wisdom (<em>sophia zētousin</em>) reflects the Hellenistic philosophical tradition from Socrates through the Sophists: the educator/philosopher demonstrated the value of his teaching through the quality of his reasoning and rhetoric.</p>',
    "23": '<p>A crucified messiah was contradictory in both Jewish and Greek frameworks: the Jewish messiah was expected to be a victorious king-warrior, not a condemned criminal executed by Rome; the Greek ideal of the hero or divine man (<em>theios anēr</em>) was one of power, beauty, and wisdom, not social shame and execution. The <em>skandalon</em> (stumbling block, scandal — also the word for the trigger of an animal trap) is not a minor offense but a complete category-violation. The cross categorically disproves both messianic and divine-hero expectations.</p>',
    "24": '<p>But to those called — both Jews and Greeks — the cross is <em>Theou dynamin kai Theou sophian</em> (God\'s power and God\'s wisdom). The calling (<em>klētos</em>) is the epistemological key: the cross is only legible as power and wisdom from within the new community constituted by the Spirit. This is not intellectual cowardice but a claim about the social location of genuine understanding: the cross can only be properly read from the inside of the community shaped by the risen Christ.</p>',
    "25": '<p>The paradox of divine weakness and divine foolishness: Paul does not claim the cross is secretly wise and powerful by human standards — he claims that God\'s apparent foolishness (<em>to mōron tou Theou</em>) exceeds all human wisdom, and God\'s apparent weakness (<em>to asthenes tou Theou</em>) exceeds all human strength. This is a real reversal, not a rhetorical trick: the cross actually defeats death through death, actually brings wisdom through what appears absurd.</p>',
    "27": '<p>The deliberate divine selection of the socially marginal is a pattern running from the OT\'s election of Israel (Deut 7:7: not because you are the most numerous), through the prophets\' preferential option for the poor, into the beatitudes (Matt 5:3-12). <em>Ta mōra tou kosmou</em> (the foolish things of the world), <em>ta asthene tou kosmou</em> (the weak things), <em>ta agene kai ta exouthenēmena</em> (the lowly and despised) — Paul is describing the actual social composition of the Corinthian church: dominated by artisans, slaves, freedpersons, and sub-elite households.</p>',
    "28": '<p><em>Ta mē onta</em> (the things that are not): Paul\'s most extreme formulation — God chose even those who do not exist in the reckoning of the powerful. In Greco-Roman status-reckoning, the poor and landless were effectively social non-entities (<em>humiles</em>). Their election as the primary recipients of the gospel is not incidental but structural to God\'s strategy of abolishing human grounds for boasting.</p>',
    "29": '<p><em>Hopōs mē kauchēsētai pasa sarx enōpion tou Theou</em> (so that no flesh may boast before God): the explicit teleology of divine election. <em>Kauchēsis</em> (boasting) in the Greco-Roman world was not mere personal vanity but the public display of honor credentials — one\'s lineage, military achievements, rhetorical victories, civic benefactions. Paul\'s argument denies any such credential access to God: divine favor is entirely grace-given, leaving no room for achievement-boasting.</p>',
    "30": '<p>Jer 9:23-24 (LXX) underlies this verse: do not boast in wisdom, strength, or riches — boast only in knowing the Lord. Paul cites it in v. 31. The application of Jeremiah\'s anti-boasting polemic to the specific Corinthian situation of wisdom-rivalry and faction demonstrates Paul\'s hermeneutic: the same divine logic that overturned Israel\'s trust in its own resources now overturns the Corinthian trust in rhetorical sophia.</p>',
    "31": '<p>The citation of Jer 9:24 closes the argument of 1:18-31 with a scriptural capstone. <em>Kauchastho en Kyriō</em> (let the one who boasts boast in the Lord): the only legitimate boast is one directed toward God, acknowledging that all gifts are received. This anti-boasting principle governs the entire letter: chapters 1-4 (wisdom), 5-6 (ethics), 7 (celibacy/marriage), 12-14 (gifts), and 15 (resurrection) all address forms of Corinthian self-congratulation that misappropriate divine gifts as grounds for personal status-claims.</p>'
  },
  "2": {
    "1": '<p>Paul\'s arrival in Corinth (Acts 18:1-5): he came from Athens having given the Areopagus speech (Acts 17:22-31), which received a polite but largely unresponsive audience. His decision to adopt a deliberately simple preaching style in Corinth may reflect a strategic response to Athens: the philosophical discourse failed; the cross will be proclaimed without rhetorical embellishment. <em>Kath\' hyperochen logou ē sophias</em> (not with superiority of speech or wisdom) — the Sophists competed for prestige through demonstrative rhetoric; Paul explicitly declines this competition.</p>',
    "2": '<p>Paul\'s deliberate (<em>ekrina</em>, I determined/decided) theological focus: know nothing among you except Jesus Christ and him crucified. Coming to Corinth — a city of philosophical schools, rhetorical competition, and religious pluralism — and declaring that the only topic worth discussing is a crucified Jewish teacher would have seemed eccentric at best, offensive at worst. The phrase is programmatic for the whole letter: every issue Paul addresses (factions, sexual ethics, food, gifts, resurrection) will be evaluated in light of the cross.</p>',
    "3": '<p><em>En astheneia kai en phobō kai en tropō pollō</em> (in weakness, fear, and much trembling): this self-description is consistent with Philippians 2:12 (work out your salvation with fear and trembling), but here Paul is describing his own apostolic experience. It may also be a deliberate rhetorical counter-display: instead of projecting the Sophistic ideal of confident authority, Paul embodies the weakness of his message. The cross-shaped apostolate looks like the crucifixion it proclaims.</p>',
    "4": '<p><em>Apodeixis pneumatos kai dynameōs</em> (demonstration of the Spirit and power): the pneumatic accompaniment of Paul\'s preaching — likely signs, healings, and the transformative impact on the hearers (cf. Gal 3:5; 1 Thess 1:5). This is the only form of rhetorical proof Paul appeals to: not logical demonstration (<em>apodeixis</em> in the philosophical sense) but Spirit-powered transformation. The choice of vocabulary is pointed — <em>apodeixis</em> was the highest form of philosophical proof; Paul redefines it as Spirit-demonstration.</p>',
    "5": '<p>The epistemological goal: faith resting on <em>dynamis Theou</em> (God\'s power), not on <em>sophia anthrōpōn</em> (human wisdom). A faith built on the rhetorical excellence of the preacher would collapse when confronted with a more eloquent Sophist — the Corinthian factionalism around Apollos is exactly this problem. Paul\'s counter-intuitive strategy (appear weak so that faith rests on God\'s power) guards the community against the fragility of persuasion-based faith.</p>',
    "6": '<p><em>Sophia de laloumen en tois teleiois</em> (we do speak wisdom among the mature): Paul distinguishes the simple gospel preaching (vv. 1-5) from a deeper wisdom taught among the spiritually mature (<em>teleioi</em>). The <em>teleioi</em> vocabulary echoes mystery-religion initiation: the <em>teleios</em> was the fully initiated member. Paul is appropriating and redefining the category: mature wisdom belongs not to the philosophically trained elite but to those indwelt by the Spirit. The wisdom is not of this age (<em>tou aiōnos toutou</em>) — it belongs to the coming age breaking into the present.</p>',
    "7": '<p><em>Sophia en mystēriō</em> (wisdom in mystery/hidden): <em>mystērion</em> in Jewish apocalyptic literature (Dan 2:19-30; 4QInstruction; 1 Enoch 103:2) denotes the divine secret now being revealed through the inspired sage or prophet. Paul\'s use of mystery language is not from Hellenistic mystery religions (which kept their initiations genuinely secret) but from Jewish apocalyptic revelation: the mystery is now being disclosed through the Spirit, not withheld from initiates. <em>Pro tōn aiōnōn</em> (before the ages): God\'s salvific plan preceded creation — the wisdom Paul proclaims is not a human discovery but a divine disclosure of what was always the plan.</p>',
    "8": '<p><em>Archontes tou aiōnos toutou</em> (the rulers of this age): probably double-referent — both the concrete human authorities (Pilate, the Sanhedrin) who orchestrated the crucifixion, and the cosmic powers/angelic authorities that Pauline cosmology identifies as dominating the present age (cf. 1 Cor 15:24; Eph 6:12; Col 2:15). Had they understood the divine wisdom of the cross, they would not have killed the Lord of glory — their ignorance was both culpable and, paradoxically, part of the divine plan.</p>',
    "9": '<p>Paul weaves together Isa 64:4 and possibly Isa 65:17 with additional material (Origen noted the surplus beyond the LXX; some ancient sources cite an <em>Apocalypse of Elijah</em> or similar apocalyptic text). The point: what God has prepared for those who love him exceeds all human epistemic categories — eye, ear, heart. This is not anti-intellectual mysticism but a claim about the limits of unaided natural knowledge: the eschatological realities are simply beyond the range of the senses and the imagination.</p>',
    "10": '<p><em>Hēmin de apekalypsen ho Theos dia tou Pneumatos</em> (God revealed these things to us through his Spirit): revelation through the Spirit is Paul\'s epistemological claim, set against both Sophistic rational demonstration and mystery-religion initiation ritual. The Spirit\'s capacity to search (<em>erauna</em>) the deep things of God (<em>ta bathe tou Theou</em>) — the language of deep-sea diving or mine exploration — implies that divine self-knowledge is the condition for genuine knowledge of divine things; the Spirit who knows God from the inside enables the believer\'s participation in that knowing.</p>',
    "11": '<p>The analogy between the human spirit and the divine Spirit: just as only a person\'s own spirit knows their inner thoughts (no external observer has epistemic access to inner mental states), so only the Spirit of God has epistemic access to the inner life of God. This is a carefully constructed argument: Paul is not making an emotional appeal but a philosophical claim about the structure of self-knowledge — genuine knowledge of God requires a share in God\'s own self-knowing faculty.</p>',
    "12": '<p><em>To pneuma tou kosmou</em> (the spirit of the world) — likely a reference to the Stoic <em>pneuma</em> that pervaded the cosmos and constituted rational consciousness. The Stoics believed human reason participated in the universal rational Spirit of the cosmos. Paul denies that this cosmic-rational Spirit gives access to the things of God: only the Spirit from God (<em>to ek Theou pneuma</em>) enables genuine theological knowledge. This is not anti-rationalism but a claim about the source and direction of true knowing.</p>',
    "13": '<p>The transmission of pneumatic wisdom through Spirit-taught words (<em>pneumatikois pneumatika synkrinō</em>): Paul claims his very vocabulary is Spirit-supplied. In Jewish prophetic tradition, the prophet does not merely relay a message but receives the words themselves (Jer 1:9; Isa 51:16). Paul applies this to apostolic teaching: the form and content of the gospel are both pneumatically given, not rhetorically constructed.</p>',
    "14": '<p><em>Psychikos anthrōpos</em> (the natural/unspiritual person): the <em>psychikos</em>/<em>pneumatikos</em> distinction reflects Hellenistic anthropological categories but Paul reframes them: being <em>psychikos</em> is not a lower anthropological grade but a description of someone who has not received the Spirit. In the mystery religions, the <em>psychikos</em> was the uninitiated; Paul agrees that there is an epistemological difference between those with and without the Spirit, but denies that it is the result of philosophical training or ritual initiation — it is the gift of the Spirit through faith.</p>',
    "15": '<p><em>Ho pneumatikos panta anakrinei</em> (the spiritual person judges/examines all things): the pneumatic person has a discernment capacity that those without the Spirit cannot evaluate. This is not spiritual elitism but a structural claim: the person shaped by the Spirit can evaluate spiritual realities from the inside, while the <em>psychikos</em> observer from the outside lacks the shared reference point. Paul will apply this epistemological claim to the Corinthian situation: those who think themselves wise by worldly standards are actually <em>psychikoi</em> unable to discern spiritual things.</p>',
    "16": '<p>Paul cites Isa 40:13 (LXX: <em>tis egnō noun Kyriou</em>, who has known the mind of the Lord?): the rhetorical answer is no human has. But the addition <em>hēmeis de noun Christou echomen</em> (we have the mind of Christ) is Paul\'s pneumatological claim: the Spirit who gives the mind of Christ to believers enables participation in the very knowing faculty of the Lord. This is not personal omniscience but Spirit-mediated participation in Christ\'s own perspective on reality. It grounds the authority of apostolic teaching while remaining entirely gift-dependent.</p>'
  },
  "3": {
    "1": '<p>The milk/solid food developmental metaphor (<em>nepiois en Christō</em>, infants in Christ) reflects the widespread educational convention in the ancient world: philosophical schools distinguished between beginners receiving elementary instruction and advanced students ready for deeper teaching. Epictetus, Philo, and Plutarch all use the milk-solid food image for this pedagogical distinction. Paul applies it to the Corinthian community: their factional behavior demonstrates that despite the spiritual gifts they display, they are functioning as spiritually immature.</p>',
    "2": '<p>The dietary metaphor is carried through: <em>gala</em> (milk) for the immature, <em>broma</em> (solid food) for the mature. In Hellenistic Jewish wisdom literature (Philo, On Husbandry 9), the milk/food metaphor specifically contrasts elementary moral instruction with advanced philosophical wisdom. Paul\'s critique is pointed: the Corinthians boast of wisdom and spiritual gifts, yet their behavior shows they have not moved beyond the elementary stage of Christian formation.</p>',
    "3": '<p><em>Sarkinoi</em> (fleshly, made of flesh): Paul\'s diagnosis of the factional behavior — zēlos (jealousy) and eris (strife) — as evidence of <em>sarx</em> (flesh-controlled) existence rather than pneumatic maturity. In Stoic ethics, faction and jealousy were paradigmatic passions (<em>pathē</em>) that indicated the absence of philosophical virtue. Paul uses similar categories but locates the cure not in philosophical training but in the Spirit\'s transformation of desire and community-orientation.</p>',
    "4": '<p>The names Paul-Apollos recur as the specific instance of the general problem. The Alexandrian philosophical tradition (Philo was the great example) combined Jewish scriptural learning with the highest Greek rhetorical and philosophical sophistication. Apollos brought this Alexandrian formation to Corinth and attracted followers among those who valued eloquence and philosophical depth. Paul\'s insistence on his own non-Sophistic style (2:1-5) was in direct contrast to Apollos\'s Alexandrian learning — creating the aesthetic-rhetorical division the factions exploited.</p>',
    "5": '<p><em>Diakonoi</em> (servants/ministers): Paul deliberately downgrading himself and Apollos from the status of patron-figures to servants. In the Greco-Roman patronal system, followers attached themselves to powerful patrons for status and benefit; Paul insists that the apostles are not patrons but slaves (<em>doulos</em>, 3:5) through whom God acts. The emphasis on God as the one who gives growth is anti-patronal: the community owes its existence to God, not to the rhetorical charisma of its founders.</p>',
    "6": '<p>The agricultural metaphor — planting and watering — describes the sequential labor of different apostles in the same field. Paul founded the Corinthian community (Acts 18:1-17); Apollos subsequently taught and deepened the community (Acts 18:27-28). The division between their followers misunderstands the relationship: they are not competing farmers but co-laborers in the same field. <em>Ho de Theos ēuxanen</em> (God was causing the growth): imperfect tense — God\'s growth-giving was continuous throughout both Paul\'s and Apollos\'s work.</p>',
    "7": '<p>The plant metaphor makes the point starkly: the planter and waterer are <em>ouden</em> (nothing) in relation to the growth; only God, who gives the growth, is significant. This is a deliberate assault on the patron-client mechanism driving the factions: if the apostles are nothing in themselves, attaching one\'s identity to them is attaching it to nothing.</p>',
    "8": '<p>Each will receive their reward (<em>misthos</em>) according to their own labor: Paul uses the agricultural wage-laborer context. The eschatological judgment will evaluate the quality of the building work (vv. 10-15), not the worker\'s rhetorical prestige. This reframes apostolic competition away from crowd-approval and toward divine evaluation — a complete inversion of the Sophistic prestige-economy.</p>',
    "9": '<p><em>Theou georgion, Theou oikodomē este</em> (you are God\'s field, God\'s building): the metaphor shifts from agriculture to architecture, anticipating the temple-building language of vv. 16-17. In Roman urbanism, a significant public building project was among the most visible displays of patronal power and civic benefaction — the building inscription naming the patron was a permanent statement of status. Paul applies the building metaphor to the community but removes the patron\'s name: it is God\'s building, not Paul\'s or Apollos\'s.</p>',
    "10": '<p>Paul as <em>sophos architektōn</em> (skilled master-builder): the <em>architektōn</em> in Roman building practice was the one who designed and supervised construction, not the one who laid individual stones. Paul\'s apostolic role is the founding design; others build upon it. The Isthmian Games at Corinth required major construction projects; the Corinthians would be familiar with large-scale building and its demands for a single reliable foundation.</p>',
    "11": '<p><em>Themelion gar allon oudeis dynatai theinai para ton keimenon, hos estin Iesous Christos</em> (no one can lay a foundation other than the one already laid, which is Jesus Christ): the metaphor has become theological claim. In Roman construction, a building was only as reliable as its foundation — on uneven rock, no superstructure was stable. Paul\'s claim: the only reliable theological foundation is Christ himself, not any apostolic personality or doctrinal innovation. The Corinthian factions are building superstructures on the wrong ground.</p>',
    "12": '<p>The building materials — gold, silver, precious stones (durable), versus wood, hay, straw (combustible) — reflect actual Roman construction practices: the wealthiest buildings used marble, granite, and costly stone; the poor built with timber and thatch. The metaphor evaluates the quality of community-building work: some contributions will endure eschatological testing, others will not. The quality is evaluated at the eschatological fire, not by contemporary prestige or popularity.</p>',
    "13": '<p><em>Hē hēmera dēlōsei</em> (the Day will reveal it): the Day of the Lord as the ultimate quality-evaluator. <em>En pyri apokalyptetai</em> (revealed by fire): fire as divine judgment is a consistent prophetic image (Amos 7:4; Isa 66:15-16; Mal 3:2). The metaphor of fire testing construction materials is from everyday experience: a fire that destroys a building reveals what was genuinely durable and what was not. The eschatological fire will similarly reveal the lasting quality of apostolic and community-building work.</p>',
    "14": '<p>The builder whose work survives the eschatological fire receives a <em>misthos</em> (reward/wage): Paul maintains the eschatological accountability of apostolic labor. This is not works-based salvation (vv. 10-15 address builders, not building-residents) but apostolic stewardship: those who build the community of God\'s people will be evaluated on the quality of their work.</p>',
    "15": '<p><em>Hōs dia pyros</em> (as though through fire): the image of barely surviving a house fire — escaping with one\'s life but losing everything accumulated. Paul is not describing punishment but loss: the builder whose work is burned survives (<em>sōthēsetai</em>) but has nothing to show. The rabbinic tradition spoke similarly of those who would inherit the world to come but with nothing to bring with them. This is pastoral warning to the apostles about the quality of their community-building work.</p>',
    "16": '<p>The community as <em>naos Theou</em> (God\'s temple): Paul makes explicit what the agricultural and architectural metaphors were approaching. In Jewish thought, the Jerusalem Temple was the dwelling-place of the divine <em>Shekhinah</em> (presence); for the Second Temple period, the Qumran community understood itself as a living temple constituted by human beings living as God\'s dwelling. Paul shares this view: the gathered community is the <em>naos</em> — the inner sanctuary, not merely the outer court. The Spirit\'s indwelling (<em>oikei</em>, present tense: is continually dwelling) constitutes the community as sacred space.</p>',
    "17": '<p><em>Ei tis ton naon tou Theou phtheirei, phtherei touton ho Theos</em> (if anyone destroys God\'s temple, God will destroy that person): the temple-protection principle applied to the community. In Jewish law, profaning the Temple was among the most serious possible offenses. Paul applies the same seriousness to community-destruction: the factional behavior, the immorality (ch. 5), the lawsuits (ch. 6) are all forms of temple-profanation. <em>Ho naos tou Theou hagios estin</em> (God\'s temple is holy) — holiness as ontological status, not merely a behavioral ideal.</p>',
    "18": '<p><em>Mēdeis heauton exapatatō</em> (do not deceive yourselves): Paul\'s diagnosis of the Corinthian problem as a form of self-deception. The person who believes they are wise by the standards of this age is epistemically confused: the standards of the present age are passing away (7:31), so wisdom by those standards is not genuine wisdom at all. <em>Mōros genesthō hina genētai sophos</em> (become a fool in order to become wise): the paradox echoes the cross-foolishness of 1:18 — genuine wisdom requires passing through apparent foolishness first.</p>',
    "19": '<p>Paul cites Job 5:13 — catching the wise in their craftiness — and Ps 94:11 (LXX 93:11) — the Lord knows the thoughts of the wise are futile. The Job citation is unusual: Eliphaz is generally not considered a reliable theological voice in Job, but Paul quotes him because the content correctly states the divine perspective. Ancient Jewish interpreters (including the Talmud) sometimes cited Eliphaz approvingly; Paul follows this practice. The Psalms citation grounds the point in Israel\'s liturgical wisdom tradition.</p>',
    "20": '<p>Psalm 94:11 (LXX 93:11) in Paul\'s citation reads <em>ton sophōn</em> (of the wise) where the MT has <em>ha-adam</em> (of humanity/man): Paul uses the LXX variant (or adapts the text) to make it applicable specifically to the wisdom-claiming Corinthians. The <em>dialogismoi</em> (thoughts, reckonings) of the wise are <em>mataioi</em> (futile, empty, vanity) — the LXX vocabulary of Ecclesiastes\' <em>hebel</em> (breath, vanity). The divine verdict on human wisdom-projects is that they are ultimately futile.</p>',
    "21": '<p><em>Mēdeis kauchastho en anthrōpois</em> (no boasting about human leaders): the anti-boasting conclusion. Paul follows this with an extraordinary counter-claim: <em>panta gar hymōn estin</em> (all things are yours). The Corinthians have been competing over which apostle to attach themselves to; Paul\'s response is that they already possess all of them — Paul, Apollos, Peter, the world, life, death, present, future — all belong to the community in Christ. The patron-client framework is completely inverted: they are not clients of the apostles but beneficiaries of a far larger endowment.</p>',
    "22": '<p>The catalogue of possessions — Paul, Apollos, Cephas, the world, life, death, present, future — moves from the specific Corinthian factions to cosmic scope. <em>Ho kosmos, zōē, thanatos, enestōta, mellonta</em>: the temporal and cosmic dimensions of existence all belong to the community in Christ. This is an eschatological claim: in Christ, the community already has access to the fullness of creation, though not yet in completed form. The Greco-Roman patron gave clients access to his resources; God in Christ gives the community access to all reality.</p>',
    "23": '<p><em>Hymeis de Christou, Christos de Theou</em> (you are of Christ, and Christ is of God): the climactic theological anchor. The community belongs to Christ, and Christ to God — a relational chain that places the community within the divine life itself. The Corinthian factions claim to belong to Paul, Apollos, or Peter; Paul says they belong to Christ, which means they already possess everything.</p>'
  },
  "4": {
    "1": '<p><em>Hypēretai Christou kai oikonomoi mystēriōn Theou</em> (servants of Christ and stewards of God\'s mysteries): two distinct role-metaphors. <em>Hypēretēs</em> was originally the under-rower on a trireme — the lowest rank of naval service, not a free professional but a functionary of the fleet. <em>Oikonomos</em> (steward/household manager): in the Greco-Roman household, the <em>oikonomos</em> was typically a trusted slave who managed the household\'s resources and represented the <em>paterfamilias</em> in business dealings. Paul applies both titles to himself — not patron-figures but functional servants of a higher authority.</p>',
    "2": '<p><em>Pistos</em> (faithful, trustworthy) is the primary qualification for a steward: the <em>oikonomos</em> must not embezzle or misrepresent his master\'s resources. Paul applies this to apostolic stewardship: faithfulness to the gospel, not rhetorical brilliance or popularity, is the criterion of genuine apostolic ministry. The Corinthian evaluation of Paul by his rhetorical performance is applying the wrong criterion.</p>',
    "3": '<p><em>Eis elachiston estin</em> (it is a very small thing to me): Paul\'s studied indifference to human evaluation — <em>anthrōpinē hēmera</em> (human day/court). The judicial language is deliberate: a <em>hēmera</em> (day) in Greco-Roman legal practice was the day of trial; the Corinthian evaluations of Paul are amateur tribunal sessions. His own self-evaluation is equally unreliable (<em>oud\' emauton anakrinō</em>), since self-knowledge is also limited. Only the Lord\'s evaluation on the Day (v. 5) is final.</p>',
    "4": '<p><em>Suneidōs</em> (conscience, literally: shared knowledge with oneself): the conscience-concept in Greco-Roman ethics referred to the inner witness that evaluated one\'s own conduct. Seneca, Cicero, and the Stoics treated the conscience as the authoritative inner court. Paul does not dismiss the conscience — it witnesses that he is not aware of anything against him — but relativizes it: the conscience is not the final court; the Lord is. A clear conscience is not the same as divine acquittal.</p>',
    "5": '<p><em>Mē pro kairou ti krinete</em> (judge nothing before the appointed time): the eschatological deferral of judgment. The final reckoning belongs to the Lord\'s Day, when <em>ta krypta tou skotous</em> (the hidden things of darkness) will be brought to light. In the context of Corinthian factional evaluation of apostles, Paul is saying: stop running your amateur tribunal on apostolic performance; God will evaluate properly at the Parousia. <em>Epainos</em> (praise) will then come to each person — the honor-verdict belongs to God to award, not to the community.</p>',
    "6": '<p><em>Metaschēmatizoō</em> (applied, transferred): Paul acknowledges that the Paul-Apollos dispute is the specific instance of a general principle he is teaching in abstract form. By speaking of himself and Apollos as examples, he avoids personalizing the critique while making it applicable to whoever is actually causing the factions. <em>To mē hyper ha gegraptai</em> (nothing beyond what is written): possibly a principle that apostolic authority is bounded by Scripture — no apostle can claim authority beyond what the OT grounds.</p>',
    "7": '<p><em>Ti de echeis ho ouk elabes</em> (what do you have that you did not receive?): Paul\'s fundamental challenge to Corinthian pride. In the Greco-Roman honor system, legitimate boasting required genuine achievements and inherited status — things that were genuinely yours. Paul\'s counter: everything you have was given, not achieved. The spiritual gifts, the wisdom, the eloquence — all received from God. Therefore all boasting is inappropriate; the language should be gratitude, not pride.</p>',
    "8": '<p><em>Ēdē kekoresmenoi este, ēdē eploutēsate, chōris hēmōn ebasileusate</em> (already you are satisfied, already you are rich, already you have begun to reign — without us!): Paul\'s ironic portrait of Corinthian over-realized eschatology. The Corinthians appear to believe they have already entered the fullness of the eschatological kingdom — <em>ēdē</em> (already) is repeated three times for emphasis. The tradition of Stoic philosophers who claimed to be kings even in chains (Epictetus Diss. 1.1) may be in the background. Paul\'s sarcasm is pointed: if you have already reigned, then the suffering apostles are left behind.</p>',
    "9": '<p>The Roman triumphal procession (<em>thriambos</em>): a victorious general would parade through Rome with his army, his spoils, and at the very end, the conquered enemies destined for execution. Paul inverts this image: God has put the apostles on display at the <em>end</em> of the procession — as those condemned to death, a spectacle (<em>theatron</em>) to the whole cosmos (angels and humans). The <em>theatron</em> metaphor is specifically theatrical: Paul and his co-workers are actors in a cosmic drama in which their humiliation is the spectacle. The Corinthians want to be in the honored section of the procession; the apostolic reality is the opposite.</p>',
    "10": '<p>The catalogue of contrasts — fools/wise, weak/strong, dishonored/honored — systematically inverts the Corinthian self-perception. The Corinthians see themselves as wise in Christ, strong, honored; Paul describes himself as the fool, the weak, the dishonored. This is the cross-shaped reality of genuine apostolic ministry: it conforms to the pattern of the crucified Christ rather than to the Sophistic ideal of the powerful sage. The irony (<em>hēmeis de atimoi</em>, we are without honor) is that the dishonored apostles are the ones who actually constitute the community the Corinthians boast in.</p>',
    "11": '<p>The peristasis catalogue (list of hardships) — a literary form used by Stoic philosophers to demonstrate the sage\'s endurance and freedom from external circumstances (Seneca Ep. 85.26; Epictetus Diss. 1.24). Paul uses the form but inverts its purpose: rather than demonstrating invulnerability through endurance, his catalogue demonstrates the pattern of the cross. <em>Gymnēteuomen kai kolaphizometha kai astatouemen</em> (we go hungry, are struck, are homeless) — specific physical deprivations that contrast sharply with the Corinthian picture of already-reigning prosperity.</p>',
    "12": '<p><em>Kopiōmen ergazomenoi tais idiais chersin</em> (we work hard with our own hands): Paul worked as a tentmaker (<em>skēnopoios</em>, Acts 18:3) — a manual laborer. In the Greco-Roman status hierarchy, manual labor was beneath the dignity of anyone with sufficient social standing to be a philosophical teacher; Sophists demanded fees for their rhetorical services, which was itself a status-marker. Paul\'s manual labor was both a practical financial decision and a deliberate status-inversion: the apostle of the crucified messiah works with his hands. The blessing/cursing, endurance/slander responses (vv. 12b-13a) echo Sermon on the Mount ethics (Matt 5:44).</p>',
    "13": '<p><em>Peripsēma tou kosmou egenēthēmen, pantōn peripsēma</em> (we have become the scum of the world, the garbage of the world): the most severe social degradation language in Paul\'s letters. <em>Peripsēma</em> (scum, filth) was the term for the residue scraped off a dirty surface, or for human sacrificial victims used to purify a community — the lowest possible social classification. Paul applies it to himself and his co-workers not as self-pity but as theological statement: the apostolic pattern conforming to the crucified Christ is the pattern of deliberate social downward-mobility.</p>',
    "14": '<p><em>Nouthetō</em> (I warn/admonish): a stronger term than simple instruction; parental correction. Paul identifies his relationship as paternal: <em>hōs tekna mou agapēta</em> (as my beloved children). In the Greco-Roman context, the relationship between a philosopher and his disciples was often described in quasi-parental terms (Seneca Ep. 2.1), but Paul makes it specifically covenantal: he has fathered them in the faith (<em>en Christō Iēsou egennēsa</em>, v. 15). The parent-child model grounds the authority of his correction without invoking the competitive patron-client framework.</p>',
    "15": '<p><em>Paidagōgous</em> (guardians, tutors): the <em>paidagōgos</em> in the Greco-Roman world was typically a trusted slave who accompanied a child to school and supervised their conduct and moral development — not the teacher but the moral custodian. Paul distinguishes his role as spiritual father from the role of <em>paidagōgoi</em> (which may refer to other teachers or apostolic figures): you may have many custodians but only one father. <em>En Christō Iēsou dia tou euaggeliou egennēsa</em> (I fathered you in Christ Jesus through the gospel): the gospel itself is the generative event, with Paul as the agent of that spiritual genesis.</p>',
    "16": '<p><em>Mimētai mou ginesthe</em> (become imitators of me): a standard Greco-Roman educational principle — the student imitates the master as the most direct form of learning. In philosophical schools, a student would follow the master\'s way of life, not merely absorb doctrines. Paul invokes this convention but grounds it christologically (v. 17: my ways in Christ). The call to imitate Paul is not ego-driven but pedagogical: Paul\'s cross-shaped life is the most direct curriculum for the cross-shaped community.</p>',
    "17": '<p>Timothy appears here as Paul\'s apostolic representative — an established pattern in Paul\'s mission practice (Phil 2:19-24; 1 Thess 3:2; Acts 19:22). Timothy\'s role is to remind them of Paul\'s ways in Christ as Paul teaches in every church — underscoring that the Corinthian situation is not unique: the same cross-shaped apostolic pattern applies universally, not just in Corinth. The universal practice claim (<em>kathos pantachou en pasē ekklēsia didaskō</em>) relativizes Corinthian exceptionalism.</p>',
    "18": '<p><em>Hōs mē erchomenou de mou pros hymas ephysiōthēsan tines</em> (some of you have become arrogant as if I were not coming): <em>phusiomenoi</em> (puffed up) — the same diagnosis as 1:12 and the signature Corinthian problem. The logic: Paul\'s absence was interpreted as inability or unwillingness to return, and some took advantage of it to advance their own influence. This is the patron-client dynamic again: with the founding patron absent, local leaders competed to fill the vacuum.</p>',
    "19": '<p><em>Eleusomar de tachos pros hymas</em> (I will come to you very soon): the apostolic authority Paul withheld from his rhetoric (2:1-5) he now asserts directly. <em>Ean ho Kyrios thelēsē</em> (if the Lord wills): the standard Jewish and early Christian qualification on plans (Jas 4:15). <em>Gnōsomai ou ton logon tōn pephysiōmenōn alla tēn dynamin</em> (I will find out not the speech of the arrogant ones but their power): Paul applies the logos/dynamis contrast (2:4) to the evaluation of the Corinthian leaders — rhetoric is not the criterion; Spirit-power is.</p>',
    "20": '<p><em>Ou gar en logō hē basileia tou Theou alla en dynamei</em> (for the kingdom of God is not a matter of talk but of power): the kingdom-language summarizes the entire argument of chs 1-4. The kingdom is not a rhetorical construct built with Sophistic skill but a pneumatic reality demonstrated through the Spirit\'s transforming power. The Corinthians\' preference for Apollos\'s eloquence is a preference for <em>logos</em> over <em>dynamis</em> — they have confused the vehicle with the reality.</p>',
    "21": '<p><em>En rhabdō elthō pros hymas ē en agapē pneumati te prautētos</em> (shall I come with a rod of discipline or in love and a spirit of gentleness?): Paul frames his coming visit as a parental choice — the disciplining rod (<em>rhabdos</em>) or the nurturing parent\'s gentleness. The <em>rhabdos</em> was the father\'s instrument of household correction; also the rod of the school disciplinarian. Paul leaves the choice to the Corinthians: their response to his letter will determine which version of fatherly Paul arrives. The rhetorical pressure of the question is designed to produce reform before his arrival.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', '1corinthians')
    merge_comm(existing, CONTEXT)
    save_comm('mkt-context', '1corinthians', existing)
    for ch in ['1', '2', '3', '4']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
